#nullable enable // autogenerated

using MVZ2.HeldItems;
using MVZ2.Vanilla.Contraptions;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Grids;
using MVZ2Logic;
using MVZ2Logic.HeldItems;
using MVZ2Logic.Level;
using PVZEngine.Entities;
using PVZEngine.Level;

namespace MVZ2.GameContent.HeldItems
{
    [HeldItemBehaviourDefinition(VanillaHeldItemBehaviourNames.emptyHandEntity)]
    public class EmptyHandEntityHeldItemBehaviour : HeldItemBehaviourDefinition
    {
        public EmptyHandEntityHeldItemBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        public override HeldTargetFlag GetHeldTargetMask(LevelEngine level)
        {
            return HeldTargetFlag.Plant | HeldTargetFlag.Enemy | HeldTargetFlag.Boss | HeldTargetFlag.Obstacle;
        }
        public override bool IsValidFor(IHeldItemTarget target, IHeldItemData data, PointerInteractionData pointerInteraction)
        {
            var pointer = pointerInteraction.pointer;
            switch (target)
            {
                case HeldItemTargetEntity entityTarget:
                    return pointer.type == PointerTypes.MOUSE && CanUseOnEntity(entityTarget.Target);
                case HeldItemTargetGrid entityGrid:
                    return pointer.type == PointerTypes.TOUCH;
            }
            return false;
        }
        public override HeldHighlight GetHighlight(IHeldItemTarget target, IHeldItemData data, PointerInteractionData pointer)
        {
            switch (target)
            {
                case HeldItemTargetEntity entityTarget:
                    {
                        var entity = entityTarget.Target;
                        var targetEntity = entity.FindPointerTargetEntity(entityTarget.PointerPosition.y, e => CanUseOnEntity(e));
                        return HeldHighlight.Entity(targetEntity);
                    }
                case HeldItemTargetGrid gridTarget:
                    {
                        if (pointer.interaction == PointerInteraction.Hold)
                        {
                            var grid = gridTarget.Target;
                            var entityTarget = grid.FindPointerTargetEntity(gridTarget.PointerPosition.y, e => CanUseOnEntity(e), out var rangeMin, out var rangeMax);
                            if (entityTarget != null)
                            {
                                return HeldHighlight.Green(grid, rangeMin, rangeMax);
                            }
                        }
                    }
                    break;
            }
            return HeldHighlight.None;
        }
        public override void OnPointerEvent(IHeldItemTarget target, IHeldItemData data, PointerInteractionData pointerParams)
        {
            if (pointerParams.IsInvalidClickButton())
                return;
            OnMainPointerEvent(target, data, pointerParams);
        }
        private void OnMainPointerEvent(IHeldItemTarget target, IHeldItemData data, PointerInteractionData pointerParams)
        {
            switch (target)
            {
                case HeldItemTargetEntity entityTarget:
                    OnPointerEventEntity(entityTarget, data, pointerParams);
                    break;
                case HeldItemTargetGrid gridTarget:
                    OnPointerEventGrid(gridTarget, data, pointerParams);
                    break;
            }
        }
        private void OnPointerEventEntity(HeldItemTargetEntity target, IHeldItemData data, PointerInteractionData pointerParams)
        {
            var entity = target.Target;
            var targetEntity = entity.FindPointerTargetEntity(target.PointerPosition.y, CanUseOnEntity);
            if (targetEntity != null && CanUseOnEntityOfPointer(targetEntity, pointerParams))
            {
                entity.Level.ResetHeldItem();
                UseOnEntity(targetEntity);
            }
        }
        private void OnPointerEventGrid(HeldItemTargetGrid target, IHeldItemData data, PointerInteractionData pointerData)
        {
            var grid = target.Target;
            var targetEntity = grid.FindPointerTargetEntity(target.PointerPosition.y, CanUseOnEntity, out _, out _);
            if (targetEntity != null && CanUseOnEntityOfPointer(targetEntity, pointerData))
            {
                grid.Level.ResetHeldItem();
                UseOnEntity(targetEntity);
            }
        }
        private bool CanUseOnEntity(Entity entity)
        {
            if (!entity.ExistsAndAlive())
                return false;
            if (entity.NoHeldTarget())
                return false;
            return entity.CanEmptyHandClick();
        }
        private bool CanUseOnEntityOfPointer(Entity entity, PointerInteractionData pointerData)
        {
            var behaviour = entity.Definition.GetBehaviour<IEmptyHandClickEntity>();
            if (behaviour == null)
                return false;
            return behaviour.IsValidPointerInteraction(entity, pointerData) && behaviour.CanEmptyHandClick(entity);
        }
        private void UseOnEntity(Entity entity)
        {
            entity.EmptyHandClick();
        }
    }
}
